var maximizeSquareArea = function(m, n, hFences, vFences) {
    const MOD = 1000000007n;
    const hs = Array.from(new Set([...hFences, 1, m])).sort((a, b) => a - b);
    const vs = Array.from(new Set([...vFences, 1, n])).sort((a, b) => a - b);
    const hdiffs = new Set();
    for (let i = 0; i < hs.length; i++) {
        for (let j = i + 1; j < hs.length; j++) {
            hdiffs.add(hs[j] - hs[i]);
        }
    }
    const vdiffs = new Set();
    for (let i = 0; i < vs.length; i++) {
        for (let j = i + 1; j < vs.length; j++) {
            vdiffs.add(vs[j] - vs[i]);
        }
    }
    let best = -1;
    for (const d of hdiffs) {
        if (vdiffs.has(d) && d > best) best = d;
    }
    if (best === -1) return -1;
    const bestBig = BigInt(best);
    return Number((bestBig * bestBig) % MOD);
};
